import React, { createContext, useContext, useState, useEffect } from 'react';
import { isAddress, getAddress } from 'ethers';
import socketService from '../utils/socket';

const ChatContext = createContext();

export const useChat = () => {
  const context = useContext(ChatContext);
  if (!context) {
    throw new Error('useChat must be used within a ChatProvider');
  }
  return context;
};

export const ChatProvider = ({ children }) => {
  const [chatRooms, setChatRooms] = useState([
    {
      id: '1',
      name: 'DeChat Genesis Holders',
      description: 'Exclusive chat for DeChat Genesis NFT holders',
      requiredNFT: 'DeChat Genesis',
      memberCount: 127,
      hasAccess: true,
      isActive: true
    },
    {
      id: '2',
      name: 'CryptoPunks Lounge',
      description: 'Chat room for CryptoPunks collectors',
      requiredNFT: 'CryptoPunks',
      memberCount: 89,
      hasAccess: true,
      isActive: false
    },
    {
      id: '3',
      name: 'BAYC Exclusive',
      description: 'Bored Ape Yacht Club members only',
      requiredNFT: 'Bored Ape Yacht Club',
      memberCount: 234,
      hasAccess: false,
      isActive: false
    }
  ]);

  const [messages, setMessages] = useState({
    '1': [],
    '2': []
  });

  const [chats, setChats] = useState([]);
  const [activeChatId, setActiveChatId] = useState(null);
  const [connectedWallet, setConnectedWallet] = useState(null);
  const [receivedMessageIds, setReceivedMessageIds] = useState(new Set());

  useEffect(() => {
    const handleNewMessage = (data) => {
      console.log('📥 New message received:', data);

      const message = {
        id: `${data.timestamp}-${Math.random().toString(36).substr(2, 9)}`,
        chatId: data.chatId,
        sender: data.sender,
        receiver: data.receiver,
        content: data.content,
        timestamp: data.timestamp
      };

      if (receivedMessageIds.has(message.id)) {
        console.log('⚠️ Duplicate message ignored:', message.id);
        return;
      }

      setReceivedMessageIds(prev => new Set([...prev, message.id]));

      setChats(prev =>
        prev.map(chat =>
          chat.id === data.chatId
            ? { ...chat, messages: [...chat.messages, message] }
            : chat
        )
      );
    };

    const handleMessageDeleted = (data) => {
      const { chatId, messageId, deleteType } = data;

      setChats(prev =>
        prev.map(chat => {
          if (chat.id === chatId) {
            return {
              ...chat,
              messages: chat.messages.map(msg => {
                if (msg.id === messageId) {
                  if (deleteType === 'forEveryone') {
                    return {
                      ...msg,
                      deletedForEveryone: true,
                      content: 'This message was deleted'
                    };
                  }
                }
                return msg;
              })
            };
          }
          return chat;
        })
      );
    };

    socketService.onNewMessage(handleNewMessage);
    socketService.onMessageDeleted(handleMessageDeleted);

    return () => {
      socketService.removeAllListeners();
    };
  }, [receivedMessageIds]);

  useEffect(() => {
    if (activeChatId) {
      console.log('🚪 Joining room:', activeChatId);
      socketService.joinRoom(activeChatId);
    }
  }, [activeChatId]);

  const connectSocket = (walletAddress) => {
    setConnectedWallet(walletAddress);
    socketService.connectSocket(walletAddress);
  };

  const disconnectSocket = () => {
    setConnectedWallet(null);
    socketService.disconnectSocket();
  };

  const createPrivateChat = (targetWalletAddress, currentAccount) => {
    if (!currentAccount) {
      return { success: false, error: 'Wallet not connected' };
    }

    if (!targetWalletAddress || !targetWalletAddress.trim()) {
      return { success: false, error: 'Please enter a wallet address' };
    }

    const trimmedAddress = targetWalletAddress.trim();

    if (!isAddress(trimmedAddress)) {
      return { success: false, error: 'Invalid Ethereum address' };
    }

    const normalizedTarget = getAddress(trimmedAddress);
    const normalizedCurrent = getAddress(currentAccount);

    if (normalizedTarget === normalizedCurrent) {
      return { success: false, error: 'You cannot chat with yourself' };
    }

    const chatId = [normalizedCurrent.toLowerCase(), normalizedTarget.toLowerCase()]
      .sort()
      .join('_');

    const existingChat = chats.find(chat => chat.id === chatId);

    if (existingChat) {
      setActiveChatId(chatId);
      return { success: true, chatId, isNew: false };
    }

    const newChat = {
      id: chatId,
      participants: [normalizedCurrent, normalizedTarget],
      messages: []
    };

    setChats(prev => [...prev, newChat]);
    setActiveChatId(chatId);

    return { success: true, chatId, isNew: true };
  };

  const sendPrivateMessage = (text) => {
    if (!activeChatId || !connectedWallet) {
      console.error('❌ Cannot send message - no active chat or wallet');
      return;
    }

    const activeChat = chats.find(chat => chat.id === activeChatId);
    if (!activeChat) return;

    const receiver = activeChat.participants.find(
      p => p.toLowerCase() !== connectedWallet.toLowerCase()
    );

    const message = {
      id: `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      chatId: activeChatId,
      sender: connectedWallet,
      receiver: receiver,
      content: text,
      timestamp: Date.now()
    };

    console.log('📤 Sending message:', message);

    setReceivedMessageIds(prev => new Set([...prev, message.id]));

    setChats(prev =>
      prev.map(chat =>
        chat.id === activeChatId
          ? { ...chat, messages: [...chat.messages, message] }
          : chat
      )
    );

    socketService.sendMessage({
      chatId: activeChatId,
      sender: connectedWallet,
      receiver: receiver,
      content: text,
      timestamp: Date.now()
    });
  };

  const deletePrivateMessage = (messageId, deleteType) => {
    if (!activeChatId) return;

    setChats(prev =>
      prev.map(chat => {
        if (chat.id === activeChatId) {
          return {
            ...chat,
            messages: chat.messages.map(msg => {
              if (msg.id === messageId) {
                if (deleteType === 'forMe') {
                  return { ...msg, deletedForMe: true };
                } else if (deleteType === 'forEveryone') {
                  socketService.sendMessage({
                    chatId: activeChatId,
                    messageId,
                    deleteType: 'forEveryone',
                    type: 'delete'
                  });
                  return {
                    ...msg,
                    deletedForEveryone: true,
                    text: 'This message was deleted'
                  };
                }
              }
              return msg;
            })
          };
        }
        return chat;
      })
    );
  };

  const getActiveChat = () => {
    return chats.find(chat => chat.id === activeChatId);
  };

  const privateChats = chats;
  const privateMessages = chats.reduce((acc, chat) => {
    acc[chat.id] = chat.messages;
    return acc;
  }, {});


  const [mintedMessages, setMintedMessages] = useState([]);

  const sendMessage = (roomId, content) => {
    const newMessage = {
      id: Date.now().toString(),
      sender: '0x742d35Cc6634C0532925a3b8D0C9C0E3C5d5c8E9',
      content,
      timestamp: new Date(),
      ipfsHash: `QmMock${Date.now()}...`,
      canMint: true
    };

    setMessages(prev => ({
      ...prev,
      [roomId]: [...(prev[roomId] || []), newMessage]
    }));
  };

  const mintMessageAsNFT = async (messageId, roomId) => {
    console.log(`Minting message ${messageId} from room ${roomId} as NFT...`);
    await new Promise(resolve => setTimeout(resolve, 2000));

    const result = {
      success: true,
      transactionHash: `0xmock${Date.now()}`,
      tokenId: Math.floor(Math.random() * 10000)
    };

    const roomMessages = messages[roomId] || [];
    const message = roomMessages.find(msg => msg.id === messageId);
    const room = chatRooms.find(r => r.id === roomId);

    if (message && room) {
      const newMintedMessage = {
        id: messageId,
        content: message.content,
        tokenId: result.tokenId.toString(),
        mintDate: new Date(),
        room: room.name,
        transactionHash: result.transactionHash
      };

      setMintedMessages(prev => [...prev, newMintedMessage]);
    }

    return result;
  };

  const createRoom = (roomData) => {
    const newRoom = {
      id: Date.now().toString(),
      name: roomData.name,
      description: roomData.description,
      type: roomData.type || 'public',
      requiredNFT: roomData.requiredNFT,
      nftContractAddress: roomData.nftContractAddress || null,
      nftOption: roomData.nftOption || null,
      existingNFTId: roomData.existingNFTId || null,
      memberCount: 1,
      hasAccess: true,
      isActive: true,
      createdBy: roomData.createdBy,
      createdAt: new Date(),
      mintPrice: roomData.mintPrice || null,
      maxSupply: roomData.maxSupply || null
    };

    setChatRooms(prev => [...prev, newRoom]);

    setMessages(prev => ({
      ...prev,
      [newRoom.id]: []
    }));

    return newRoom;
  };

  const deleteRoom = (roomId) => {
    setChatRooms(prev => prev.filter(room => room.id !== roomId));

    setMessages(prev => {
      const newMessages = { ...prev };
      delete newMessages[roomId];
      return newMessages;
    });
  };

  const removeMintedMessage = (messageId) => {
    setMintedMessages(prev => prev.filter(msg => msg.id !== messageId));
  };

  const leaveRoom = (roomId) => {
    setChatRooms(prev => prev.map(room => {
      if (room.id === roomId) {
        return {
          ...room,
          hasAccess: false,
          memberCount: Math.max(0, room.memberCount - 1)
        };
      }
      return room;
    }));
  };

  const value = {
    chatRooms,
    messages,
    privateChats,
    privateMessages,
    chats,
    activeChatId,
    mintedMessages,
    sendMessage,
    sendPrivateMessage,
    deletePrivateMessage,
    createPrivateChat,
    getActiveChat,
    mintMessageAsNFT,
    createRoom,
    deleteRoom,
    removeMintedMessage,
    leaveRoom,
    connectSocket,
    disconnectSocket
  };

  return (
    <ChatContext.Provider value={value}>
      {children}
    </ChatContext.Provider>
  );
};
